  int n,temp,sum=0,digits=0;
  scanf("%d", &n);
  temp = n;
  while(temp!=0){digits++; temp/=10;}
  temp = n;
  while(temp!=0){sum += pow(temp%10,digits); temp/=10;}
  if(sum==n) printf("Armstrong"); else printf("Not Armstrong");
  return 0;
}
```

